concept.syntax:
// Simple enum
enum Direction { North, South, East, West }

// Enum with data
enum Shape {
    Circle(f64),              // radius
    Rectangle(f64, f64),      // width, height
}

// Option<T> — built in
let maybe: Option<i32> = Some(42);
let nothing: Option<i32> = None;

// Access with match
match maybe {
    Some(v) => println!("{}", v),
    None    => println!("nothing"),
}

demo.code:
enum Coin {
    Penny,
    Nickel,
    Dime,
    Quarter,
}

fn value(c: Coin) -> u32 {
    match c {
        Coin::Penny   => 1,
        Coin::Nickel  => 5,
        Coin::Dime    => 10,
        Coin::Quarter => 25,
    }
}

fn main() {
    let c = Coin::Quarter;
    println!("cents = {}", value(c));

    let score: Option<i32> = Some(88);
    if let Some(n) = score {
        println!("score = {}", n);
    }
}

