practice.solutionCode:
enum Season {
    Spring, Summer, Autumn, Winter,
}

fn is_warm(s: Season) -> bool {
    match s {
        Season::Spring | Season::Summer => true,
        _ => false,
    }
}

fn main() {
    println!("{}", is_warm(Season::Summer));
}
